record_types.code:
type Host_Key_Ops is record
   Sign   : access function (Key : Byte_Array; Data : Byte_Array) return Byte_Array;
   Verify : access function
     (Key : Byte_Array; Data : Byte_Array; Signature : Byte_Array) return Boolean;
end record;

type KEX_Crypto_Ops is record
   Flow                  : KEX_Flow_Type := Standard_DH;
   Pubkey_Byte_Len       : Natural       := 0;
   Is_Hybrid             : Boolean       := False;
   PQ_PK_Len             : Natural       := 0;
   PQ_CT_Len             : Natural       := 0;
   Trad_PK_Len           : Natural       := 0;
   Hash                  : access function (Data : Byte_Array) return Byte_Array;
   Generate_Keypair      : access procedure
     (Random :     Random_Generator; P, G : Byte_Array; Priv : out Byte_Array;
      Pub    : out Byte_Array);
   Compute_Shared_Secret : access procedure
     (Own_Priv   :        Byte_Array; Peer_Pub : Byte_Array; P, G : Byte_Array;
      Reply      : in out Byte_Array; Reply_Len : in out Natural; Shared : in out Byte_Array;
      Shared_Len :    out Natural);
   Select_Group          : access procedure
     (Min, N, Max : Uint32; P, G : out Byte_Array; P_Len, G_Len : out Natural) :=
     null;
   Compute_H             : access procedure
     (V_C, V_S : Byte_Array; I_C, I_S : Byte_Array; K_S : Byte_Array; E, F, K : Byte_Array;
      H        : out Byte_Array; H_Len : out Natural);
   Compute_H_GEX         : access procedure
     (V_C, V_S : Byte_Array; I_C, I_S : Byte_Array; K_S : Byte_Array; Min, N, Max : Uint32;
      P, G, E, F, K : Byte_Array; H : out Byte_Array; H_Len : out Natural) :=
     null;
   Derive_Keys           : access procedure
     (K, H, Session_ID         : Byte_Array; Cipher_Key_Len_C2S, MAC_Key_Len_C2S : Positive;
      IV_Len_C2S               :     Natural; Cipher_Key_Len_S2C, MAC_Key_Len_S2C : Positive;
      IV_Len_S2C               :     Natural; IV_c2s, IV_s2c : out Byte_Array;
      Enc_Key_c2s, Enc_Key_s2c : out Byte_Array; MAC_Key_c2s, MAC_Key_s2c : out Byte_Array);
end record;
